import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Basic premium calculation ---
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("single sword (no modifiers, newcomer first contract) → 100 base + 10 first + 5 fee = 115 G");
  it.todo("single amulet (no modifiers, newcomer first contract) → 60 + 6 + 5 = 71 G");
  it.todo("single staff (no modifiers, newcomer first contract) → 80 + 8 + 5 = 93 G");
  it.todo("single potion (no modifiers, newcomer first contract) → 40 + 4 + 5 = 49 G");

  // --- Components and block discount ---
  it.todo("2 runes → base 50 G (no block)");
  it.todo("3 runes → base 60 G (block applies)");
  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base 175 G (no block at 7)");
  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword newcomer first contract → 100 + 50 curse + 10 first + 5 fee = 165 G");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("second contract → follow-up discount applies");

  // --- Modifier scope on multi-item policy ---
  it.todo("cursed sword + plain amulet → policy base 160 + 50 curse = 210 G before fee/policy-wide");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → rounded up to 198 G");
  it.todo("payout yielding 350.5 G → rounded down to 350 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (enchantment 3) → 165 G");
  it.todo("long-standing customer (3y) second contract, cursed sword enchantment 7 → 160 G");

  // --- Claim: basic and deductible ---
  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
  it.todo("rune (no enchantment/material) damage 200 G → payout 100 G");
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Claim: enchantment and dragon clauses ---
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (full, then deductible)");
  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");

  // --- Multiple items of the same type ---
  it.todo("policy with two swords, both damaged → each treated as separate damage with own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI rejects whole claim");

  // --- Cap exhaustion ---
  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium modifiers do not raise cap → cap remains 2000");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block does not reduce insurance sum)");
  it.todo("sword cap 2000: two claims of 1500 → first payout 1400 (cap 600), second payout 600 (cap 0)");

  // --- Edge cases / CLI errors ---
  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
  it.todo("claim references item not in policy → CLI exits non-zero, writes stderr");
  it.todo("claim damage with negative amount → CLI exits non-zero, writes stderr");
});

