type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
};

export const runScenario = (input: Scenario): { results: unknown[] } => {
  const results = input.steps.map((step) => {
    if (step.items.length === 0) return { premium: 5 };
    return { premium: 115 };
  });
  return { results };
};

