type Item = {
  type: string;
  cursed?: boolean;
  enchantment?: number;
  material?: string;
};
type Step = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const groupCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const baseForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_BASE;
  }
  return count * ITEM_BASE[type];
};

const calculatePolicyBase = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of groupCountsByType(items)) {
    total += baseForGroup(type, count);
  }
  return total;
};

const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);

const curseSurcharge = (item: Item): number =>
  item.cursed ? ITEM_BASE[item.type] * CURSE_SURCHARGE_RATE : 0;

const itemSpecificSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + curseSurcharge(item), 0);

const quotePremium = ({ items }: Step): number => {
  const policyBase = calculatePolicyBase(items);
  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
  const itemSurcharges = itemSpecificSurcharges(items);
  const rawPremium = policyBase + itemSurcharges + firstContractSurcharge + PROCESSING_FEE;
  return roundUpInMHPCOsFavor(rawPremium);
};

export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
  const results = steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

